  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"./generated/prisma\"\n}\n\n// --- 1. USER & PERSONALIZATION ---\n\nmodel User {\n  id        String   @id @default(cuid())\n  email     String   @unique\n  gender    Gender // Specifically MALE or FEMALE\n  interests String[] // Student tags for AI context\n\n  settings   UserSettings?\n  selections UserSelection[]\n  createdAt  DateTime        @default(now())\n}\n\nenum Gender {\n  MALE\n  FEMALE\n}\n\nmodel UserSettings {\n  id     String @id @default(cuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id])\n\n  // Stores UI colors (analogyBox, keywordBox), AI API keys, etc.\n  config Json @default(\"{\\\"theme\\\": \\\"light\\\", \\\"colors\\\": {}}\")\n\n  updatedAt DateTime @updatedAt\n}\n\n// --- 2. CONTENT HIERARCHY (The Tree) ---\n\nmodel Unit {\n  id      String       @id @default(cuid())\n  title   String\n  summary UnitSummary?\n  lessons Lesson[]\n\n  // High-level connections\n  analogies MasterAnalogy[]\n  keywords  MasterKeyword[]\n  examples  Example[]\n  exercises Exercise[]\n  tagLinks  TagRelator[]\n}\n\nmodel Lesson {\n  id    String @id @default(cuid())\n  title String\n  depth Int    @default(0) // For indentation logic\n  order Int // Sequence in the sidebar\n\n  // Recursive Tree Structure\n  parentId String?\n  parent   Lesson?  @relation(\"SubLessons\", fields: [parentId], references: [id])\n  children Lesson[] @relation(\"SubLessons\")\n\n  unitId String?\n  unit   Unit?   @relation(fields: [unitId], references: [id])\n\n  paragraphs MasterParagraph[]\n  analogies  MasterAnalogy[]\n  keywords   MasterKeyword[]\n  examples   Example[]\n  exercises  Exercise[]\n  tagLinks   TagRelator[]\n}\n\nmodel MasterParagraph {\n  id        String  @id @default(cuid())\n  content   String  @db.Text\n  order     Int // Position within the lesson\n  isDefault Boolean @default(true)\n\n  lessonId String\n  lesson   Lesson @relation(fields: [lessonId], references: [id])\n\n  // Layout Modules\n  boxes Box[]\n\n  // Relations\n  analogies  MasterAnalogy[]\n  examples   Example[]\n  tagLinks   TagRelator[]\n  selections UserSelection[]\n}\n\n// --- 3. DYNAMIC LAYOUT & STATIC TOOLS ---\n\nmodel Box {\n  id      String  @id @default(cuid())\n  title   String?\n  logo    String? // Icon name (e.g., \"warning\", \"info\")\n  content Json // Stores text or interactive object data\n\n  paragraphId String\n  paragraph   MasterParagraph @relation(fields: [paragraphId], references: [id])\n\n  placement Placement @default(AFTER)\n  order     Int       @default(0)\n}\n\nenum Placement {\n  BEFORE\n  AFTER\n}\n\nmodel MasterKeyword {\n  id         String @id @default(cuid())\n  word       String\n  definition String @db.Text\n\n  unitId   String?\n  unit     Unit?   @relation(fields: [unitId], references: [id])\n  lessonId String?\n  lesson   Lesson? @relation(fields: [lessonId], references: [id])\n\n  tagLinks TagRelator[]\n}\n\nmodel Example {\n  id       String @id @default(cuid())\n  question Json // Supports LaTeX/Math\n  answer   String @db.Text\n\n  unitId      String?\n  unit        Unit?            @relation(fields: [unitId], references: [id])\n  lessonId    String?\n  lesson      Lesson?          @relation(fields: [lessonId], references: [id])\n  paragraphId String?\n  paragraph   MasterParagraph? @relation(fields: [paragraphId], references: [id])\n}\n\nmodel Exercise {\n  id   String @id @default(cuid())\n  type String // \"REVIEW\", \"QUIZ\", \"LAB\"\n  data Json // Multi-choice, True/False, etc.\n\n  unitId   String?\n  unit     Unit?   @relation(fields: [unitId], references: [id])\n  lessonId String?\n  lesson   Lesson? @relation(fields: [lessonId], references: [id])\n}\n\nmodel UnitSummary {\n  id      String @id @default(cuid())\n  content String @db.Text\n  unitId  String @unique\n  unit    Unit   @relation(fields: [unitId], references: [id])\n}\n\n// --- 4. TAGGING & ANALYTICS (The Brain) ---\n\nmodel Tag {\n  id     String       @id @default(cuid())\n  name   String       @unique\n  labels String[]\n  links  TagRelator[]\n}\n\nmodel TagRelator {\n  id    String @id @default(cuid())\n  tagId String\n  tag   Tag    @relation(fields: [tagId], references: [id])\n\n  // Sentiment tracking for the AI\n  likes    Int @default(0)\n  dislikes Int @default(0)\n\n  // Polymorphic Links (Handled with XOR logic in App)\n  unitId      String?\n  unit        Unit?            @relation(fields: [unitId], references: [id])\n  lessonId    String?\n  lesson      Lesson?          @relation(fields: [lessonId], references: [id])\n  paragraphId String?\n  paragraph   MasterParagraph? @relation(fields: [paragraphId], references: [id])\n  analogyId   String?\n  analogy     MasterAnalogy?   @relation(fields: [analogyId], references: [id])\n  keywordId   String?\n  keyword     MasterKeyword?   @relation(fields: [keywordId], references: [id])\n}\n\nmodel MasterAnalogy {\n  id        String  @id @default(cuid())\n  content   String  @db.Text\n  category  String // e.g., \"Farming\"\n  isDefault Boolean @default(false)\n\n  unitId      String?\n  unit        Unit?            @relation(fields: [unitId], references: [id])\n  lessonId    String?\n  lesson      Lesson?          @relation(fields: [lessonId], references: [id])\n  paragraphId String?\n  paragraph   MasterParagraph? @relation(fields: [paragraphId], references: [id])\n\n  tagLinks   TagRelator[]\n  selections UserSelection[]\n}\n\nmodel UserSelection {\n  id     String @id @default(cuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  masterParagraphId String\n  paragraph         MasterParagraph @relation(fields: [masterParagraphId], references: [id])\n\n  activeAnalogyId String?\n  activeAnalogy   MasterAnalogy? @relation(fields: [activeAnalogyId], references: [id])\n\n  @@unique([userId, masterParagraphId])\n}\n",
